THOUGHT: The miscompile is due to sinking subtraction into select and later converting to addition that swaps select arms, exposing poison from "sub nsw 0, X". We need to add a guard in SinkSubIntoSelect to bail out if either select arm is a potentially-poisonous nsw negate. I'll insert a check right after matching the select operands and before proceeding, then run submit-patch to validate.

```bash
python3 - << 'PY'
import re
p='llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp'
s=open(p,'r').read()
pattern = r'(if \(!match\(Select, m_OneUse\(m_Select\(m_Value\(Cond\), m_Value\(TrueVal\),\s*m_Value\(FalseVal\)\)\)\)\)\)\s*return nullptr;\s*?)'
guard = r"""\1
      {
        using namespace llvm::PatternMatch;
        Value *NX;
        bool TruePoison = match(TrueVal, m_Sub(m_Zero(), m_Value(NX))) &&
                          isa<BinaryOperator>(TrueVal) &&
                          cast<BinaryOperator>(TrueVal)->hasNoSignedWrap();
        NX = nullptr;
        bool FalsePoison = match(FalseVal, m_Sub(m_Zero(), m_Value(NX))) &&
                           isa<BinaryOperator>(FalseVal) &&
                           cast<BinaryOperator>(FalseVal)->hasNoSignedWrap();
        if (TruePoison || FalsePoison)
          return nullptr;
      }
"""
s2, n = re.subn(pattern, guard, s, flags=re.M)
open(p,'w').write(s2)
print("Inserted guard matches:", n)
PY
&& submit-patch
```

