THOUGHT: The miscompile occurs when InstCombine sinks a subtraction into select arms and later rewrites it, potentially swapping select arms and exposing poison from a "sub nsw 0, X". To fix this safely, I will add a guard in the SinkSubIntoSelect helper within InstCombineAddSub.cpp: after confirming the select match and that the OtherHandOfSub is one of the select arms, bail out if either select arm is a potentially-poisonous nsw negation (i.e., "sub nsw 0, V"). I'll implement this edit with a Python script and then run submit-patch to validate.

```bash
python3 - << 'PY'
import re, subprocess, sys

path = 'llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp'
s = open(path,'r').read()

# Clean any previously malformed guard blocks to ensure idempotence.
s = re.sub(r'(if \(OtherHandOfSub != TrueVal && OtherHandOfSub != FalseVal\)\s*\{[\s\S]*?return nullptr;\s*\})',
           'if (OtherHandOfSub != TrueVal && OtherHandOfSub != FalseVal)\n        return nullptr;',
           s)

# Pattern to find the sequence: match(select ...) return nullptr; then membership check and return nullptr;
pat = (r'(if \(!match\(Select, m_OneUse\(m_Select\(m_Value\(Cond\), m_Value\(TrueVal\),\s*m_Value\(FalseVal\)\)\)\)\)\)\s*'
       r'return nullptr;\s*'
       r'if \(OtherHandOfSub != TrueVal && OtherHandOfSub != FalseVal\)\s*'
       r'return nullptr;\s*)')

guard = r"""\1      {
        using namespace llvm::PatternMatch;
        Value *NX;
        bool TruePoison = match(TrueVal, m_Sub(m_Zero(), m_Value(NX))) &&
                          isa<BinaryOperator>(TrueVal) &&
                          cast<BinaryOperator>(TrueVal)->hasNoSignedWrap();
        NX = nullptr;
        bool FalsePoison = match(FalseVal, m_Sub(m_Zero(), m_Value(NX))) &&
                           isa<BinaryOperator>(FalseVal) &&
                           cast<BinaryOperator>(FalseVal)->hasNoSignedWrap();
        if (TruePoison || FalsePoison)
          return nullptr;
      }
"""

s2, n = re.subn(pat, guard, s, flags=re.M)
if n == 0:
    print("Failed to insert guard: pattern not found", file=sys.stderr)
else:
    open(path,'w').write(s2)
    print("Inserted guard occurrences:", n)

# Run submit-patch to validate
try:
    res = subprocess.run(['submit-patch'], stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True)
    print(res.stdout)
except FileNotFoundError:
    print("submit-patch not found", file=sys.stderr)
PY
```

